#!/usr/bin/env python3
"""Audio Patchwork Steganography — embed hidden data in audio."""
import struct
import random
import hashlib
import os

class AudioWatermark:
    """Patchwork steganography: modify sample pairs to encode bits."""
    SYNC_PATTERN = 0xA5A5
    VERSION = 4

    def __init__(self, delta=2000, pairs_per_bit=1000, segment_size=4410):
        self.delta = delta
        self.pairs_per_bit = pairs_per_bit
        self.segment_size = segment_size

    def _crc16(self, data):
        crc = 0xFFFF
        for byte in data:
            crc ^= byte
            for _ in range(8):
                crc = (crc >> 1) ^ 0xA001 if crc & 1 else crc >> 1
        return crc & 0xFFFF

    def _pack_payload(self, subscriber_id, timestamp):
        core = struct.pack('>BQI', (self.VERSION << 4), subscriber_id, timestamp)
        return struct.pack('>H', self.SYNC_PATTERN) + core + struct.pack('>H', self._crc16(core))

    def _to_bits(self, data):
        return [(b >> (7-i)) & 1 for b in data for i in range(8)]

    def _get_groups(self, bit_idx, seg_len):
        random.seed(bit_idx * 1000 + 42)
        n = min(self.pairs_per_bit, seg_len // 3)
        indices = list(range(seg_len))
        random.shuffle(indices)
        return indices[:n], indices[n:2*n]

    def embed(self, samples, subscriber_id, timestamp):
        """Embed watermark in audio samples (list of int16 values)."""
        result = list(samples)
        payload = self._pack_payload(subscriber_id, timestamp)
        bits = self._to_bits(payload)
        n_bits = len(bits)
        seg = self.segment_size
        n_copies = (len(result) // seg) // n_bits

        for copy in range(n_copies):
            for i, bit in enumerate(bits):
                start = (copy * n_bits + i) * seg
                if start + seg > len(result):
                    break
                ga, gb = self._get_groups(i, seg)
                for idx in ga:
                    result[start + idx] = max(-32768, min(32767, result[start + idx] + (self.delta if bit else -self.delta)))
                for idx in gb:
                    result[start + idx] = max(-32768, min(32767, result[start + idx] + (-self.delta if bit else self.delta)))
        return result

    def detect(self, samples):
        """Detect and extract watermark from audio samples."""
        seg = self.segment_size
        payload_bytes = 17  # sync(2) + core(13) + crc(2)
        n_bits = payload_bytes * 8
        votes = [0.0] * n_bits

        n_copies = (len(samples) // seg) // n_bits
        for copy in range(n_copies):
            for i in range(n_bits):
                start = (copy * n_bits + i) * seg
                if start + seg > len(samples):
                    break
                ga, gb = self._get_groups(i, seg)
                mean_a = sum(samples[start + idx] for idx in ga) / len(ga) if ga else 0
                mean_b = sum(samples[start + idx] for idx in gb) / len(gb) if gb else 0
                votes[i] += (mean_a - mean_b)

        bits = [1 if v > 0 else 0 for v in votes]
        data = bytes(sum(bits[i+j] << (7-j) for j in range(8)) for i in range(0, len(bits), 8))

        # Verify
        if len(data) >= 17:
            sync = struct.unpack('>H', data[0:2])[0]
            if sync == self.SYNC_PATTERN:
                core = data[2:15]
                checksum = struct.unpack('>H', data[15:17])[0]
                if checksum == self._crc16(core):
                    _, sub_id, ts = struct.unpack('>BQI', core)
                    return {'subscriber_id': sub_id, 'timestamp': ts, 'verified': True}
        return {'verified': False}

