"""Audio Watermark Detection — extract embedded data from audio."""
import struct
import random

class WatermarkDetector:
    SYNC_PATTERN = 0xA5A5

    def __init__(self, pairs_per_bit=1000, segment_size=4410):
        self.pairs_per_bit = pairs_per_bit
        self.segment_size = segment_size

    def _crc16(self, data):
        crc = 0xFFFF
        for byte in data:
            crc ^= byte
            for _ in range(8):
                crc = (crc >> 1) ^ 0xA001 if crc & 1 else crc >> 1
        return crc & 0xFFFF

    def _get_groups(self, bit_idx, seg_len):
        random.seed(bit_idx * 1000 + 42)
        n = min(self.pairs_per_bit, seg_len // 3)
        indices = list(range(seg_len))
        random.shuffle(indices)
        return indices[:n], indices[n:2*n]

    def detect(self, samples):
        """Detect watermark and return subscriber info if found."""
        seg = self.segment_size
        n_bits = 17 * 8  # 17 bytes payload
        n_copies = (len(samples) // seg) // n_bits
        if n_copies == 0:
            return None

        votes = [0.0] * n_bits
        for copy in range(n_copies):
            for i in range(n_bits):
                start = (copy * n_bits + i) * seg
                if start + seg > len(samples):
                    break
                ga, gb = self._get_groups(i, seg)
                mean_a = sum(samples[start+idx] for idx in ga) / max(len(ga), 1)
                mean_b = sum(samples[start+idx] for idx in gb) / max(len(gb), 1)
                votes[i] += (mean_a - mean_b)

        bits = [1 if v > 0 else 0 for v in votes]
        data = bytes(sum(bits[i+j]<<(7-j) for j in range(8)) for i in range(0, len(bits), 8))

        if len(data) >= 17:
            sync = struct.unpack('>H', data[:2])[0]
            if sync == self.SYNC_PATTERN:
                core = data[2:15]
                crc = struct.unpack('>H', data[15:17])[0]
                if crc == self._crc16(core):
                    _, sub_id, ts = struct.unpack('>BQI', core)
                    return {'subscriber_id': sub_id, 'timestamp': ts}
        return None

