"""LSB Image Steganography — hide data in least significant bits."""
import struct
import os

class LSBEmbed:
    """Embed secret data in image pixel LSBs."""

    MAGIC = b'LSB1'

    def embed(self, pixels, width, height, channels, secret_data):
        """Embed data in pixel array. pixels = flat list of byte values."""
        # Prepare payload: magic + length + data
        payload = self.MAGIC + struct.pack('>I', len(secret_data)) + secret_data
        bits = []
        for byte in payload:
            for i in range(8):
                bits.append((byte >> (7-i)) & 1)

        max_bits = len(pixels)
        if len(bits) > max_bits:
            raise ValueError(f'Data too large: need {len(bits)} bits, have {max_bits} pixels')

        result = list(pixels)
        for i, bit in enumerate(bits):
            result[i] = (result[i] & 0xFE) | bit
        return result

    def extract(self, pixels):
        """Extract hidden data from pixel LSBs."""
        # Read bits
        bits = [p & 1 for p in pixels]

        def bits_to_bytes(bit_list):
            return bytes(sum(bit_list[i+j]<<(7-j) for j in range(8)) for i in range(0, len(bit_list), 8))

        # Check magic
        header_bits = bits[:64]  # 8 bytes = magic(4) + length(4)
        if len(header_bits) < 64:
            return None
        header = bits_to_bytes(header_bits)
        if header[:4] != self.MAGIC:
            return None
        length = struct.unpack('>I', header[4:8])[0]

        # Extract payload
        total_bits = 64 + length * 8
        if total_bits > len(bits):
            return None
        data_bits = bits[64:total_bits]
        return bits_to_bytes(data_bits)

