"""LSB Image Extraction — extract hidden data from image LSBs."""
import struct

class LSBExtract:
    MAGIC = b'LSB1'

    def extract(self, pixels):
        """Extract hidden data from pixel LSBs. pixels = flat list of byte values."""
        if len(pixels) < 64:
            return None
        bits = [p & 1 for p in pixels]
        header = bytes(sum(bits[i+j]<<(7-j) for j in range(8)) for i in range(0, 64, 8))
        if header[:4] != self.MAGIC:
            return None
        length = struct.unpack('>I', header[4:8])[0]
        total = 64 + length * 8
        if total > len(bits):
            return None
        data_bits = bits[64:total]
        return bytes(sum(data_bits[i+j]<<(7-j) for j in range(8)) for i in range(0, len(data_bits), 8))

    def detect(self, pixels):
        """Check if pixels contain LSB-embedded data."""
        if len(pixels) < 64:
            return False
        bits = [p & 1 for p in pixels[:32]]
        magic = bytes(sum(bits[i+j]<<(7-j) for j in range(8)) for i in range(0, 32, 8))
        return magic == self.MAGIC

