#!/usr/bin/env python3
"""CRC-16 Integrity Check — multiple CRC-16 variants."""

class CRC16:
    @staticmethod
    def crc16_modbus(data):
        """CRC-16/MODBUS (poly 0xA001)."""
        crc = 0xFFFF
        for byte in data:
            crc ^= byte
            for _ in range(8):
                crc = (crc >> 1) ^ 0xA001 if crc & 1 else crc >> 1
        return crc & 0xFFFF

    @staticmethod
    def crc16_ccitt(data):
        """CRC-16/CCITT (poly 0x1021)."""
        crc = 0xFFFF
        for byte in data:
            crc ^= byte << 8
            for _ in range(8):
                crc = ((crc << 1) ^ 0x1021) & 0xFFFF if crc & 0x8000 else (crc << 1) & 0xFFFF
        return crc

    @staticmethod
    def crc16_xmodem(data):
        """CRC-16/XMODEM."""
        crc = 0
        for byte in data:
            crc ^= byte << 8
            for _ in range(8):
                crc = ((crc << 1) ^ 0x1021) & 0xFFFF if crc & 0x8000 else (crc << 1) & 0xFFFF
        return crc

    @staticmethod
    def verify(data, expected_crc, variant='modbus'):
        funcs = {'modbus': CRC16.crc16_modbus, 'ccitt': CRC16.crc16_ccitt, 'xmodem': CRC16.crc16_xmodem}
        return funcs.get(variant, CRC16.crc16_modbus)(data) == expected_crc

