#!/usr/bin/env python3
"""Binary Message Framing — pack/unpack structured binary messages."""
import struct
import hashlib

class BinaryFramer:
    """Frame binary messages with length prefix, type, and CRC integrity."""
    MAGIC = b'\xFE\xED'
    HEADER_FMT = '>2sHBH'  # magic(2) + length(2) + type(1) + seq(2)
    HEADER_SIZE = struct.calcsize(HEADER_FMT)

    def __init__(self):
        self.sequence = 0

    def _crc16(self, data):
        crc = 0xFFFF
        for b in data:
            crc ^= b
            for _ in range(8):
                crc = (crc >> 1) ^ 0xA001 if crc & 1 else crc >> 1
        return crc & 0xFFFF

    def pack(self, msg_type, payload):
        """Pack payload into framed message."""
        self.sequence = (self.sequence + 1) % 65536
        header = struct.pack(self.HEADER_FMT, self.MAGIC, len(payload), msg_type, self.sequence)
        crc = struct.pack('>H', self._crc16(header + payload))
        return header + payload + crc

    def unpack(self, data):
        """Unpack framed message. Returns (msg_type, sequence, payload) or None."""
        if len(data) < self.HEADER_SIZE + 2:
            return None
        magic, length, msg_type, seq = struct.unpack(self.HEADER_FMT, data[:self.HEADER_SIZE])
        if magic != self.MAGIC:
            return None
        if len(data) < self.HEADER_SIZE + length + 2:
            return None
        payload = data[self.HEADER_SIZE:self.HEADER_SIZE + length]
        crc_expected = struct.unpack('>H', data[self.HEADER_SIZE + length:self.HEADER_SIZE + length + 2])[0]
        if self._crc16(data[:self.HEADER_SIZE] + payload) != crc_expected:
            return None
        return (msg_type, seq, payload)

    def find_frame(self, stream):
        """Find first valid frame in byte stream."""
        for i in range(len(stream) - self.HEADER_SIZE):
            if stream[i:i+2] == self.MAGIC:
                result = self.unpack(stream[i:])
                if result:
                    return (i, result)
        return None
